def _to_float(value):
    try:
        return float(value)
    except Exception:
        return None

def transform(input_data):
    rows = input_data if isinstance(input_data, list) else []
    cleaned = []
    for row in rows:
        mpg = _to_float(row.get('mpg'))
        hp = _to_float(row.get('hp'))
        if mpg is None or hp is None:
            continue
        row = dict(row)
        row['mpg'] = mpg
        row['hp'] = hp
        row['power_band'] = 'high' if hp >= 150 else ('mid' if hp >= 90 else 'low')
        cleaned.append(row)
    return cleaned
